option.value:
# Script para corregir problemas de sincronización de AGP
Write-Host "Limpiando caches de Gradle..." -ForegroundColor Green

# Detener todos los demonios de Gradle
& .\gradlew --stop

# Limpiar el proyecto
& .\gradlew clean

# Limpiar cache local de Gradle
if (Test-Path "$env:USERPROFILE\.gradle\caches") {
    Write-Host "Limpiando cache de Gradle..." -ForegroundColor Yellow
    Remove-Item "$env:USERPROFILE\.gradle\caches" -Recurse -Force -ErrorAction SilentlyContinue
}

# Limpiar archivos de build locales
if (Test-Path "build") {
    Remove-Item "build" -Recurse -Force -ErrorAction SilentlyContinue
}

if (Test-Path "app\build") {
    Remove-Item "app\build" -Recurse -Force -ErrorAction SilentlyContinue
}

if (Test-Path "orabel\build") {
    Remove-Item "orabel\build" -Recurse -Force -ErrorAction SilentlyContinue
}

Write-Host "Forzando descarga de dependencias..." -ForegroundColor Green
& .\gradlew build --refresh-dependencies

Write-Host "Proceso completado!" -ForegroundColor Green

# Script para corregir problemas de sincronización de AGP
Write-Host "Limpiando caches de Gradle..." -ForegroundColor Green

# Detener todos los demonios de Gradle
Write-Host "Deteniendo demonios de Gradle..." -ForegroundColor Yellow
& .\gradlew --stop

# Limpiar el proyecto
Write-Host "Limpiando proyecto..." -ForegroundColor Yellow
& .\gradlew clean

# Limpiar cache local de Gradle
if (Test-Path "$env:USERPROFILE\.gradle\caches") {
    Write-Host "Limpiando cache de Gradle..." -ForegroundColor Yellow
    try {
        Remove-Item "$env:USERPROFILE\.gradle\caches" -Recurse -Force -ErrorAction Stop
        Write-Host "Cache de Gradle eliminada exitosamente" -ForegroundColor Green
    } catch {
        Write-Host "Advertencia: No se pudo eliminar completamente la cache de Gradle" -ForegroundColor Red
    }
}

# Limpiar archivos de build locales
Write-Host "Limpiando directorios build locales..." -ForegroundColor Yellow

if (Test-Path "build") {
    Remove-Item "build" -Recurse -Force -ErrorAction SilentlyContinue
    Write-Host "Directorio build/ eliminado" -ForegroundColor Green
}

if (Test-Path "app\build") {
    Remove-Item "app\build" -Recurse -Force -ErrorAction SilentlyContinue
    Write-Host "Directorio app/build/ eliminado" -ForegroundColor Green
}

if (Test-Path "orabel\build") {
    Remove-Item "orabel\build" -Recurse -Force -ErrorAction SilentlyContinue
    Write-Host "Directorio orabel/build/ eliminado" -ForegroundColor Green
}

# Eliminar archivos .gradle locales si existen
if (Test-Path ".gradle") {
    Remove-Item ".gradle" -Recurse -Force -ErrorAction SilentlyContinue
    Write-Host "Directorio .gradle/ local eliminado" -ForegroundColor Green
}

Write-Host "Forzando descarga de dependencias con AGP 8.9.0..." -ForegroundColor Green
& .\gradlew build --refresh-dependencies

Write-Host "¡Proceso completado exitosamente!" -ForegroundColor Green
Write-Host "Ahora puedes abrir Android Studio y sincronizar el proyecto." -ForegroundColor Cyan

# Script de corrección forzada para problemas graves de Gradle Write-Host "=== CORRECCIÓN FORZADA DE GRADLE Y AGP ===" -ForegroundColor Cyan
# 1. Terminar todos los procesos Java/Gradle Write-Host "1. Terminando procesos Java..." -ForegroundColor Yellow Get-Process -Name "java" -ErrorAction SilentlyContinue | Stop-Process -Force Get-Process -Name "gradle*" -ErrorAction SilentlyContinue | Stop-Process -Force
# 2. Eliminar TODA la caché de Gradle globalmente Write-Host "2. Eliminando caché global de Gradle..." -ForegroundColor Yellow $gradleDir = "$env:USERPROFILE\.gradle" if (Test-Path $gradleDir) { Remove-Item $gradleDir -Recurse -Force -ErrorAction SilentlyContinue Write-Host " Cache global eliminada" -ForegroundColor Green }
# 3. Eliminar directorios locales problemáticos Write-Host "3. Limpiando directorios locales..." -ForegroundColor Yellow @(".gradle", "build", "app\build", "orabel\build", ".idea\caches") | ForEach-Object { if (Test-Path $_) { Remove-Item $_ -Recurse -Force -ErrorAction SilentlyContinue Write-Host " Eliminado: $_" -ForegroundColor Green } }
# 4. Recrear wrapper de Gradle Write-Host "4. Verificando wrapper de Gradle..." -ForegroundColor Yellow if (!(Test-Path "gradlew.bat") -or !(Test-Path "gradle\wrapper\gradle-wrapper.jar")) { Write-Host " Recreando wrapper..." -ForegroundColor Red # Descargar wrapper si está corrupto Invoke-WebRequest -Uri "https://services.gradle.org/distributions/gradle-8.11.1-bin.zip" -OutFile "gradle-temp.zip" Expand-Archive "gradle-temp.zip" -DestinationPath "gradle-temp" -Force Copy-Item "gradle-temp\gradle-8.11.1\bin\gradle.bat" -Destination "gradlew.bat" -Force Remove-Item "gradle-temp*" -Recurse -Force }
# 5. Configurar variables de entorno temporales $env:GRADLE_OPTS = "-Xmx4g -Dfile.encoding=UTF-8 -Dkotlin.daemon.jvm.options=-Xmx2g" $env:JAVA_OPTS = "-Xmx2g"
Write-Host "5. Configuración de memoria aplicada" -ForegroundColor Green
# 6. Test básico de Gradle Write-Host "6. Probando Gradle wrapper..." -ForegroundColor Yellow Start-Process -FilePath "cmd.exe" -ArgumentList "/c", "gradlew.bat", "--version" -Wait -NoNewWindow
Write-Host "=== CORRECCIÓN COMPLETADA ===" -ForegroundColor Cyan Write-Host "Ahora ejecuta: .\gradlew.bat clean build" -ForegroundColor Green
